class Solution:
    def smallestSubsequence(self, s):
        import itertools
        distinct = sorted(set(s))
        # build greedily by trying smallest feasible char at each step (brute feasibility)
        result = []
        remaining = s
        chosen = set()
        while len(chosen) < len(distinct):
            from collections import Counter
            cnt = Counter(remaining)
            for c in sorted(set(remaining)):
                if c in chosen:
                    continue
                idx = remaining.index(c)
                rest = remaining[idx + 1:]
                need = set(distinct) - chosen - {c}
                if need <= set(rest):
                    result.append(c)
                    chosen.add(c)
                    remaining = ''.join(ch for ch in rest if ch not in chosen)
                    break
        return ''.join(result)

